'use client'

import { Suspense, useEffect, useState } from 'react'
import { useSearchParams, useRouter } from 'next/navigation'
import { signIn } from 'next-auth/react'
import { Spinner } from '@/components/ui/spinner'

/**
 * Nest GitHub OAuth redirects here with ?access_token=<JWT>.
 * We exchange that for a NextAuth session so the UI keeps working,
 * while GitHub tokens remain stored on the Nest user (survives sign-out of Next session
 * only if user signs back in with the same account — token is on server).
 */
function GithubCompleteInner() {
  const searchParams = useSearchParams()
  const router       = useRouter()
  const [message, setMessage] = useState('Completing sign-in…')

  useEffect(() => {
    const token = searchParams.get('access_token')
    if (!token) {
      setMessage('Missing token. Start GitHub connect from the app again.')
      return
    }

    let cancelled = false
    void (async () => {
      const res = await signIn('credentials', {
        nestJwt:  token,
        redirect: false,
      })
      if (cancelled) return
      if (res?.error) {
        setMessage('Could not start session. Try logging in with email and password, then connect GitHub again.')
        return
      }
      window.history.replaceState({}, '', '/auth/github-complete')
      router.replace('/dashboard')
      router.refresh()
    })()

    return () => { cancelled = true }
  }, [searchParams, router])

  return (
    <div className="min-h-[40vh] flex flex-col items-center justify-center gap-4 p-8">
      <Spinner size="md" />
      <p className="font-mono text-[13px] text-text-muted text-center max-w-md">{message}</p>
    </div>
  )
}

export default function GithubCompletePage() {
  return (
    <Suspense
      fallback={(
        <div className="min-h-[40vh] flex items-center justify-center">
          <Spinner size="md" />
        </div>
      )}
    >
      <GithubCompleteInner />
    </Suspense>
  )
}
